final:
module RefModule(CLK,Rst,Sm,M);input CLK,Rst,Sm;
	reg [2:0]count;
	output wire M;


	always @ (posedge CLK)
			if (Rst|M) 
				count=3'd0;
			else if (Sm)
				count=count+1'b1;
		   else 
				count=count;

		  wire _n01 = count[0] ^ 3'b001[0];
  wire _n02 = count[1] ^ 3'b001[1];
  wire _n03 = count[2] ^ 3'b001[2];
  wire _n04 = count[3] ^ 3'b001[3];
  assign M = ~_n01 & ~_n02 & ~_n03 & ~_n04;


endmodule
